  <!-- SillyTavern 将替换 <choice> 为以下结构，$1 到 $5 为外部正则捕获内容 -->
  <div class="choice-container">
    <div class="choice-toggle">选择你的行动吧~♫</div>
    <div class="choice-menu">
      <div class="choice-item" data-choice="$1">$1</div>
      <div class="choice-item" data-choice="$2">$2</div>
      <div class="choice-item" data-choice="$3">$3</div>
      <div class="choice-item" data-choice="$4">$4</div>
      <div class="choice-item" data-choice="$5">$5</div>
    </div>
  </div>

  <script>
    // 添加交互逻辑
    document.querySelectorAll('.choice-toggle').forEach(toggle => {
      toggle.addEventListener('click', () => {
        const menu = toggle.nextElementSibling;
        menu.classList.toggle('active');
      });
    });

    document.querySelectorAll('.choice-item').forEach(item => {
      item.addEventListener('click', async () => {
        const choiceText = item.getAttribute('data-choice');
        await triggerSlash(`/setinput ${choiceText}`);
        // 隐藏菜单
        item.parentElement.classList.remove('active');
      });
    });
  </script>
